import pandas as pd, json
from datetime import datetime

oi = pd.DataFrame(var_call_vOxHrMCt4nQ2BVBGnOzxy6AS)
cases = pd.DataFrame(var_call_SPlI3Isd6D9XUw4YflipPbUA)

def norm(s):
    if s is None:
        return None
    return str(s).replace('#','').strip()

oi['oi_id_norm'] = oi['Id'].map(norm)
valid_oi = set(oi['oi_id_norm'].tolist())

cases['oi_id_norm'] = cases['orderitemid__c'].map(norm)
cases['issue_norm'] = cases['issue_id'].map(norm)

# window: past 5 months from 2023-01-16 -> 2022-08-16 inclusive
start = pd.Timestamp('2022-08-16T00:00:00Z')
end = pd.Timestamp('2023-01-16T23:59:59Z')

def parse_ts(x):
    try:
        return pd.to_datetime(x, utc=True)
    except Exception:
        return pd.NaT

cases['created_ts'] = cases['createddate'].map(parse_ts)
flt = cases[cases['oi_id_norm'].isin(valid_oi) & cases['created_ts'].between(start, end) & cases['issue_norm'].notna()]

counts = flt.groupby('issue_norm').size().sort_values(ascending=False)
issue_id = counts.index[0] if len(counts)>0 else None

print('__RESULT__:')
print(json.dumps({'issue_id': issue_id}))

